<div class="wp-block-group"><!-- wp:heading {"level":3,"fontSize":"heading-small"} -->
<h3 class="wp-block-heading has-heading-small-font-size">What is a UK Apostille?</h3>
<!-- /wp:heading -->

<!-- wp:paragraph {"fontSize":"medium"} -->
<p class="has-medium-font-size">The term apostille is used to describe the process of having the authenticity of a document certified so it will be accepted in a foreign jurisdiction. A UK document will be submitted to the UK apostille authority to receive an apostille certificate.</p>
<!-- /wp:paragraph -->

<!-- wp:paragraph {"fontSize":"medium"} -->
<p class="has-medium-font-size">After a UK document has received an apostille, it will be recognized in the other countries that have signed the Hague Apostille Convention (the majority of countries internationally).</p>
<!-- /wp:paragraph --></div>
<!-- /wp:group -->

<!-- wp:group {"metadata":{"name":"Content Column"},"style":{"spacing":{"blockGap":"var:preset|spacing|40"}},"layout":{"type":"constrained"}} -->
